import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input received from a form or any input source
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Encoding user input to prevent XSS attacks
        String encodedUserInput = Encode.forHtml(userInput);

        // Properly handling user input with encoding
        String output = "Welcome, " + encodedUserInput;

        System.out.println(output);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
